import type { Topic } from "./types.js";

/**
 * Deterministically derive a 32-byte swarm topic from a per-user secret.
 *
 * Must be a one-way hash so the on-the-wire topic never reveals the secret, and
 * stable so every device of the same user derives the identical topic.
 *
 * TODO(crush): implement with sodium-universal `crypto_generichash` (BLAKE2b)
 * over `userSecret` with a fixed personalization/context string
 * (e.g. "keating:p2p:topic:v1"). Return a 32-byte Uint8Array.
 */
export function deriveTopic(_userSecret: Uint8Array): Topic {
  throw new Error("TODO(crush): deriveTopic not implemented");
}

export interface SwarmHandle {
  /** Number of currently connected peers. */
  readonly peerCount: number;
  /** Resolves once flushed/announced on the DHT. */
  ready(): Promise<void>;
  /** Tear down all connections and leave the topic. */
  destroy(): Promise<void>;
  /** Subscribe to peer-count changes. Returns an unsubscribe fn. */
  onPeerChange(listener: (count: number) => void): () => void;
}

/**
 * Join `topic` and pipe every peer connection into the replication stream
 * produced by `replicate` (a Corestore.replicate(socket) call from store.ts).
 *
 * TODO(crush): implement using `hyperswarm`:
 *   - new Hyperswarm({ keyPair? })
 *   - swarm.on('connection', (conn) => replicate(conn))
 *   - const discovery = swarm.join(topic, { server: true, client: true })
 *   - await discovery.flushed()
 *   - track peers via swarm.on('connection'/'update') and notify listeners
 *   - destroy() => await swarm.destroy()
 */
export function joinSwarm(
  _topic: Topic,
  _replicate: (socket: import("node:stream").Duplex) => void,
): SwarmHandle {
  throw new Error("TODO(crush): joinSwarm not implemented");
}

