import { app, BrowserWindow } from "electron";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";
import { P2PStore, createP2PStorageBackend } from "@keating/p2p-core";
import { registerP2PIpc } from "./ipc.js";

const __dirname = dirname(fileURLToPath(import.meta.url));

/**
 * Load or create the per-user 32-byte secret that derives the swarm topic and
 * this device's writable core namespace.
 *
 * TODO(crush): persist a generated secret under app.getPath('userData') (e.g.
 * 'keating-user-secret.bin'); create with sodium randombytes if absent. For v1
 * you may also accept KEATING_USER_SECRET (hex) to pair against a known seeder.
 */
function loadUserSecret(): Uint8Array {
  throw new Error("TODO(crush): loadUserSecret not implemented");
}

async function createWindow(): Promise<void> {
  const window = new BrowserWindow({
    width: 1200,
    height: 800,
    webPreferences: {
      preload: join(__dirname, "preload.js"),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: true,
    },
  });

  // Boot the P2P store in the main process and expose it to the renderer
  // strictly through the typed IPC bridge.
  const store = await P2PStore.open({
    storageDir: join(app.getPath("userData"), "p2p"),
    userSecret: loadUserSecret(),
    label: `desktop:${process.platform}`,
  });
  const backend = createP2PStorageBackend(store);
  registerP2PIpc(window, backend);

  app.on("before-quit", () => {
    void store.close();
  });

  const devServer = process.env.KEATING_DEV_SERVER;
  if (devServer) {
    await window.loadURL(devServer);
  } else {
    // Production: load the static web build.
    await window.loadFile(join(__dirname, "../../web/dist/index.html"));
  }
}

app.whenReady().then(async () => {
  await createWindow();
  app.on("activate", () => {
    if (BrowserWindow.getAllWindows().length === 0) void createWindow();
  });
});

app.on("window-all-closed", () => {
  if (process.platform !== "darwin") app.quit();
});

