392	export async function verifyRecoveryChallenge(
393		storage: DioStorage,
394		email: string,
395		otp: string,
396	): Promise<boolean> {
397		const key = recoveryStorageKey(email);
398		const value = await storage.getItem(key);
399		if (!value || typeof value !== "object") {
400			return false;
401		}
402		const challenge = value as RecoveryChallenge;
403		if (challenge.attempts >= 5) {
404			return false;
405		}
406		if (new Date(challenge.expiresAt) < new Date()) {
407			await storage.setItem(key, { ...challenge, attempts: challenge.attempts + 1 });
408			return false;
409		}
410		const expectedHash = Buffer.from(challenge.otpHash, "hex");
411		const actualHash = Buffer.from(hashOtp(otp), "hex");
412		if (expectedHash.length !== actualHash.length) {
413			await storage.setItem(key, { ...challenge, attempts: challenge.attempts + 1 });
414			return false;
415		}
416		const ok = timingSafeEqual(expectedHash, actualHash);
417		if (!ok) {
418			await storage.setItem(key, { ...challenge, attempts: challenge.attempts + 1 });
419			return false;
420		}
421		await storage.setItem(key, { ...challenge, attempts: challenge.attempts + 1 });
422		return true;
423	}
