425	function isEventLockStale(record: DioEventRecord): boolean {
426		if (record.status !== "processing") return false;
427		const createdAt = record.createdAt ? new Date(record.createdAt).getTime() : 0;
428		return Number.isFinite(createdAt) && Date.now() - createdAt > EVENT_LOCK_TTL_MS;
429	}
