431	/** In-process serialization of lock attempts for the same event id. */
432	const eventLockPromises = new Map<string, Promise<boolean>>();
433	
434	async function acquireEventLockUncontended(storage: DioStorage, eventId: string): Promise<boolean> {
435		const key = eventStorageKey(eventId);
436		const existing = await storage.getItem(key);
437		if (existing && typeof existing === "object") {
438			const record = existing as DioEventRecord;
439			if (record.status === "succeeded") return false;
440			if (record.status === "processing" && !isEventLockStale(record)) return false;
441			// Stale "processing" lock or "failed" record: fall through and attempt
442			// to overwrite with a new lock.
443		}
444	
445		const lockId = cryptoUUID();
446		const record: DioEventRecord = {
447			status: "processing",
448			createdAt: new Date().toISOString(),
449			lockId,
450		};
451	
452		// Attempt an atomic write. Drivers that support {@code nx} will reject if the
453		// key already exists; drivers that do not support it will perform a plain set.
454		// The re-read below verifies that this process won the race.
455		try {
456			await storage.setItem(key, record, { nx: true });
457		} catch {
458			// nx may have been honored and failed, or the driver may have rejected the
459			// unknown option. Either way, verify ownership with the re-read.
460		}
461	
462		const reRead = await storage.getItem(key);
463		if (!reRead || typeof reRead !== "object") {
464			return false;
465		}
466		const reReadRecord = reRead as DioEventRecord;
467		return reReadRecord.status === "processing" && reReadRecord.lockId === lockId;
468	}
