470	/**
471	 * Acquire a per-event processing lock using a dedicated storage key.
472	 *
473	 * Returns false if the event has already succeeded or is currently being
474	 * processed by another worker. A previously "failed" event can be retried, and
475	 * "processing" locks older than {@link EVENT_LOCK_TTL_MS} are treated as stale
476	 * and may be re-acquired.
477	 *
478	 * The public entry point serializes callers for the same event within this
479	 * process, so multiple concurrent webhooks for one event cannot race here. The
480	 * underlying storage write attempts an atomic set-if-not-exists ({@code nx:
481	 * true}) when the driver supports it, then verifies ownership by reading the
482	 * stored lock id. For cross-process or multi-instance deployments, this relies
483	 * on the storage backend honoring {@code nx} (Redis, KV, etc.) or otherwise
484	 * providing linearizable writes; filesystem-backed storage without an atomic
485	 * CAS primitive cannot give a hard distributed-lock guarantee.
486	 */
487	export async function acquireEventLock(storage: DioStorage, eventId: string): Promise<boolean> {
488		const previous = eventLockPromises.get(eventId);
489		const current = (async () => {
490			await previous;
491			return acquireEventLockUncontended(storage, eventId);
492		})();
493		eventLockPromises.set(eventId, current);
494		try {
495			return await current;
496		} finally {
497			if (eventLockPromises.get(eventId) === current) {
498				eventLockPromises.delete(eventId);
499			}
500		}
501	}
