575	function isValidEmail(email: string): boolean {
576		return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
577	}
578	
579	function cryptoUUID(): string {
580		if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
581			return crypto.randomUUID();
582		}
583		const bytes = new Uint8Array(16);
584		if (typeof crypto !== "undefined" && typeof crypto.getRandomValues === "function") {
585			crypto.getRandomValues(bytes);
586		} else {
587			for (let i = 0; i < bytes.length; i++) {
588				bytes[i] = Math.floor(Math.random() * 256);
589			}
590		}
591		bytes[6] = (bytes[6] & 0x0f) | 0x40;
592		bytes[8] = (bytes[8] & 0x3f) | 0x80;
593		const hex = Array.from(bytes, (b) => b.toString(16).padStart(2, "0")).join("");
594		return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20)}`;
595	}
